// Generated by GitHub Copilot
import { useMemo, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { FiSearch, FiUserPlus, FiUsers } from 'react-icons/fi'
import PageHeader from '../../components/ui/PageHeader.jsx'
import Card from '../../components/ui/Card.jsx'
import Button from '../../components/ui/Button.jsx'
import Input from '../../components/ui/Input.jsx'
import Select from '../../components/ui/Select.jsx'
import Pagination from '../../components/ui/Pagination.jsx'
import EmptyState from '../../components/ui/EmptyState.jsx'
import { TableSkeleton } from '../../components/ui/Skeleton.jsx'
import MembersTable from '../../components/tables/MembersTable.jsx'
import { useData } from '../../hooks/useData.js'
import { usePagination } from '../../hooks/usePagination.js'

/** Admin members list with search, status filter and pagination. */
export default function Members() {
  const { members, loading } = useData()
  const navigate = useNavigate()
  const [query, setQuery] = useState('')
  const [status, setStatus] = useState('all')

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase()
    return members.filter((m) => {
      const matchesQuery =
        !q ||
        m.name.toLowerCase().includes(q) ||
        m.mobile.includes(q) ||
        m.email.toLowerCase().includes(q)
      const matchesStatus = status === 'all' || m.status?.toLowerCase() === status
      return matchesQuery && matchesStatus
    })
  }, [members, query, status])

  const { page, totalPages, pageItems, next, prev, goTo } = usePagination(
    filtered,
    8,
  )

  return (
    <div>
      <PageHeader
        title="Members"
        description={`${members.length} members in the fund`}
        action={
          <Button
            icon={FiUserPlus}
            onClick={() => navigate('/admin/members/add')}
          >
            Add Member
          </Button>
        }
      />

      <Card className="p-4">
        <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
          <Input
            name="search"
            icon={FiSearch}
            placeholder="Search by name, mobile or email"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            className="flex-1"
          />
          <Select
            name="status"
            value={status}
            onChange={(e) => setStatus(e.target.value)}
            className="sm:w-44"
            options={[
              { value: 'all', label: 'All statuses' },
              { value: 'active', label: 'Active' },
              { value: 'inactive', label: 'Inactive' },
            ]}
          />
        </div>

        <div className="mt-4">
          {loading ? (
            <TableSkeleton rows={6} cols={6} />
          ) : filtered.length === 0 ? (
            <EmptyState
              icon={FiUsers}
              title="No members found"
              description="Try adjusting your search or filter."
            />
          ) : (
            <>
              <MembersTable members={pageItems} />
              <Pagination
                page={page}
                totalPages={totalPages}
                onNext={next}
                onPrev={prev}
                onGoTo={goTo}
              />
            </>
          )}
        </div>
      </Card>
    </div>
  )
}
